BEGIN;

-- Stores the raw source material for evaluation.
CREATE TABLE IF NOT EXISTS transcripts (
  id INTEGER PRIMARY KEY,
  sha256 TEXT NOT NULL UNIQUE,
  path TEXT,
  content TEXT NOT NULL,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP
);

-- Stores the ground-truth question/answer pairs generated by the expert model.
CREATE TABLE IF NOT EXISTS qa_pairs (
  id INTEGER PRIMARY KEY,
  transcript_id INTEGER NOT NULL,
  question TEXT NOT NULL,
  answer TEXT NOT NULL,
  -- The exact text span from the transcript that supports the answer.
  span TEXT,
  created_at TEXT DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(transcript_id) REFERENCES transcripts(id),
  UNIQUE(transcript_id, question)
);

-- Records each evaluation run.
CREATE TABLE IF NOT EXISTS runs (
  id INTEGER PRIMARY KEY,
  started_at TEXT DEFAULT CURRENT_TIMESTAMP,
  candidate_model TEXT NOT NULL,
  -- Store run settings (e.g., prompts, model params) for reproducibility.
  settings_json TEXT
);

-- Stores the results for each question in a given run.
CREATE TABLE IF NOT EXISTS results (
  run_id INTEGER NOT NULL,
  qa_id INTEGER NOT NULL,
  candidate_answer TEXT NOT NULL,
  faithfulness REAL,
  relevancy REAL,
  judge_score REAL,
  PRIMARY KEY(run_id, qa_id),
  FOREIGN KEY(run_id) REFERENCES runs(id),
  FOREIGN KEY(qa_id) REFERENCES qa_pairs(id)
);

COMMIT;
